//-------------------------------------------------------------------------
// 배부반영여부 체크설정
//-------------------------------------------------------------------------
scwin.f_chkYn = function () {
  if (chk_distCdYn.getValue() == '1') {
    gr_result.setColumnVisible('distAmt', true);
  } else {
    gr_result.setColumnVisible('distAmt', false);
  }
  ;
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
  if (!(await $c.gus.cfValidate($p, [ed_retrieveDate, ed_acctDeptCd]))) return;

  //실적월, 회계부서 validate 체크
  let jsonData = {
    "retrieveDate": ed_retrieveDate.getValue(),
    "acctDeptCd": ed_acctDeptCd.getValue(),
    "regId": scwin.userId,
    "userpattern": acb_userpattern.getValue()
  };
  dma_retrieve.setJSON(jsonData);
  $c.sbm.execute($p, sbm_retrieve);
};

// f_grdHeiht 실행 후 확인
//-------------------------------------------
// 그리드 데이터 엑셀로 다운
//-------------------------------------------
scwin.f_runExcel = async function () {
  let totCnt = ds_Result.getTotalRow();
  if (totCnt == 0) {
    $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
    return;
  }
  ;
  const retConfirm = await $c.win.confirm($p, "EXCEL로 다운로드 받으시겠습니까?");
  if (!retConfirm) return;
  let sheetTitle = "거래처별손익실적집계";
  const options = {
    fileName: sheetTitle + ".xlsx",
    sheetName: sheetTitle
  };
  $c.data.downloadGridViewExcel($p, gr_result, options);
};

