scwin.gridFormat = function (data, formattedData, rowIndex, colIndex) {
  let colID = gr_result.getColumnID(colIndex);
  let numValid = $c.num.isNumber($p, data);
  let validColID = ['ttAmt', 'pchsAmt', 'unSellAmtThis', 'innerSellAmt', 'innerPchsAmt', 'sellAmt', 'unPchsAmtThis', 'sellTotAmt', 'pchsTotAmt', 'pchsVarAmt', 'pchsFixAmt'];
  if (data == "") return data;
  if (!validColID.includes(scwin.realColID[colID])) return formattedData;
  if (numValid) {
    return $c.num.formatNumber($p, data);
  } else {
    return formattedData;
  }
  ;
};
